#include <bits/stdc++.h>
using namespace std;
const int N=65,M=32010;
int n,m,v[N],p[N],q[N],s[N][2],f[N][M];
int main(){
    scanf("%d%d",&m,&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d%d",&v[i],&p[i],&q[i]);
        if(q[i]){
            if(s[q[i]][0])
                s[q[i]][1]=i;
            else
                s[q[i]][0]=i;
        }
    }
    for(int i=1;i<=n;i++)
        for(int j=1;j<=m;j++){
            f[i][j]=f[i-1][j];
            if(!q[i]){
                int a=s[i][0],b=s[i][1];
                if(j>=v[i])
                    f[i][j]=max(f[i][j],f[i-1][j-v[i]]+v[i]*p[i]);
                if(a && j>=v[i]+v[a])
                    f[i][j]=max(f[i][j],f[i-1][j-v[i]-v[a]]+v[i]*p[i]+v[a]*p[a]);
                if(b && j>=v[i]+v[b])
                    f[i][j]=max(f[i][j],f[i-1][j-v[i]-v[b]]+v[i]*p[i]+v[b]*p[b]);
                if(b && j>=v[i]+v[a]+v[b])
                    f[i][j]=max(f[i][j],f[i-1][j-v[i]-v[a]-v[b]]+v[i]*p[i]+v[a]*p[a]+v[b]*p[b]);
            }
        }
    printf("%d",f[n][m]);
    return 0;
}
